  public static Solution createRuntimeSolution(Language language, String languageRootPath, MPSProject project) throws IOException {
    // FIXME with new code, don't create rt under language, rather a sibling
    IFile basePath = project.getFileSystem().getFile(languageRootPath).findChild("runtime");
    String namespace = language.getModuleName() + ".runtime";

    Solution runtime = new SolutionProducer(project).create(namespace, basePath);
    // XXX perhaps, can configure SolutionProducer with an extra code to create a model, not to perform ModuleDependencyVersions.update twice?
    EditableSModel runtimeModel = createModel(runtime, namespace);
    runtimeModel.save();

    new ModuleDependencyVersions(project.getComponent(LanguageRegistry.class), project.getRepository()).update(runtime);
    runtime.save();
    return runtime;
  }

  public static Solution createSandboxSolution(Language language, String languageRootPath, MPSProject project) throws IOException {
    // XXX I don't think it's smart to create sandbox inside language dir. Rather have to be its sibling
    String basePath = languageRootPath + File.separator + "sandbox";
    String namespace = language.getModuleName() + ".sandbox";

    IFile descriptorFile = NewModuleUtil.getModuleFile(namespace, project.getFileSystem().getFile(basePath), MPSExtentions.DOT_SOLUTION);
    assert !(descriptorFile.exists());
    SolutionDescriptor descriptor = SolutionProducer.createSolutionDescriptor(namespace, descriptorFile);

    // XXX I don't see a reason to use Language.getAllExtendedLanguages, but this is the way it was introduced in 5057107c
    {
      Iterator<Language> extLang_it = SetSequence.fromSet(language.getAllExtendedLanguages()).iterator();
      Language extLang_var;
      while (extLang_it.hasNext()) {
        extLang_var = extLang_it.next();
        SLanguage extSLang = MetaAdapterFactory.getLanguage(extLang_var.getModuleReference());
        descriptor.getLanguageVersions().put(extSLang, extLang_var.getLanguageVersion());
      }
    }

    Solution sandbox = (Solution) new GeneralModuleFactory().instantiate(descriptor, descriptorFile);
    project.addModule(sandbox);
    sandbox.save();

    SModelInternal sandboxModel = (SModelInternal) createModel(sandbox, namespace);
    SLanguage l = MetaAdapterFactory.getLanguage(language.getModuleReference());
    sandboxModel.addLanguage(l);
    sandboxModel.setLanguageImportVersion(l, language.getLanguageVersion());
    ((EditableSModel) sandboxModel).save();

    new ModuleDependencyVersions(project.getComponent(LanguageRegistry.class), project.getRepository()).update(sandbox);

    sandbox.save();
    return sandbox;
  }

